import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  世界: z.object({
    日期: z.string().prefault('腊月十五'),
    时间: z.string().prefault('上午十点'),
    天气: z.string().prefault('晴，零下二十三度'),
    当前地点: z.string().prefault('张桂兰的民宿'),
  }),

  在场NPC: z.record(
    z.string().describe('NPC称呼'),
    z.object({
      基本信息: z.object({
        年龄: z.string().or(z.literal('待初始化')).prefault('待初始化'),
        身份: z.string().or(z.literal('待初始化')).prefault('待初始化'),
        家庭状况: z.string().or(z.literal('待初始化')).prefault('待初始化'),
        类型: z.enum(['直球型', '借口型', '服务型', '闷骚型', '竞争型', '外来型']).or(z.literal('待初始化')).prefault('待初始化'),
      }),
      身材: z.string().or(z.literal('待初始化')).prefault('待初始化'),
      穿搭: z.object({
        当前穿着: z.string().or(z.literal('待初始化')).prefault('待初始化'),
        是否本地人: z.boolean().prefault(true),
      }),
      性格: z.string().or(z.literal('待初始化')).prefault('待初始化'),
      侵犯值: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(20),
      内心想法: z.string().or(z.literal('待初始化')).prefault('待初始化'),
      当前状态: z.string().or(z.literal('待初始化')).prefault('待初始化'),
    })
  ).prefault({}),
});

$(() => {
  registerMvuSchema(Schema);
})

