        '吉 - 你找到借口脱身,"我朋友还等着我呢"',
        '吉 - 她只是开开玩笑,摸了几把就算了',
        '吉 - 她老公突然打电话,她接电话时你溜了'
      ],
      5: [
        '大吉 - 突然来了快递电话,你借机离开',
        '大吉 - 有熟人经过叫你,她不好当着人的面动手',
        '大吉 - 外面有人敲门,"有人在吗",她只好放开你',
        '大吉 - 暴雪停了,通知说路通了,车能走'
      ],
      6: [
        '天佑 - 暴雪停了,你马上收拾东西准备撤',
        '天佑 - 你提前发现酒有问题,没喝',
        '天佑 - 她突然被叫去处理急事,暂时放过你',
        '天佑 - 来了一车新游客,女人们注意力被分散'
      ]
    };

    function copyToDialog(text) {
      try {
        parent.$("#send_textarea").val(text);
        return true;
      } catch (error) {
        return false;
      }
    }

    function showToast(msg, type = '') {
      const toast = $('#toast');
      toast.text(msg).removeClass('success error').addClass(type).addClass('show');
      setTimeout(() => { toast.removeClass('show'); }, 2000);
    }

    function getAllVariables() {
      return Mvu.getMvuData({ type: 'message', message_id: getCurrentMessageId() });
    }

    function switchFont(fontName) {
      $('body').removeClass('font-a font-b font-c font-d').addClass(`font-${fontName}`);
      $('.font-btn').removeClass('active');
      $(`.font-btn[data-font="${fontName}"]`).addClass('active');
      try {
        if (typeof localStorage !== 'undefined') {
          localStorage.setItem('xuexiang_font', fontName);
        }
      } catch (e) {}
    }

    function getDangerStage(value) {
      if (value <= 20) return '收敛 - 偷偷瞄、保持距离';
      if (value <= 40) return '试探 - 盯着看、找借口靠近、碰手';
      if (value <= 70) return '明显 - 直勾勾盯、主动贴上来、直接上手摸';
      return '动手 - 直接动手、按住不让动、撕衣服';
    }

    function calculateEndings() {
      const data = getAllVariables();
      const npcList = _.get(data, 'stat_data.在场NPC', {});

      let totalDanger = 0;
      let npcCount = 0;

      Object.values(npcList).forEach(npc => {
        if (npc !== '待初始化' && typeof npc === 'object') {
          totalDanger += (npc.侵犯值 || 0);
          npcCount++;
        }
      });

      const avgDanger = npcCount > 0 ? totalDanger / npcCount : 0;

      let probabilities = {
        escape: Math.max(5, 70 - avgDanger * 0.7),
        submit: Math.min(40, avgDanger * 0.4),
        toy: Math.min(35, avgDanger * 0.35),
        exclusive: npcCount === 1 ? Math.min(30, avgDanger * 0.3) : 0,
        famous: npcCount >= 3 ? Math.min(40, avgDanger * 0.4) : 0
      };

      const total = Object.values(probabilities).reduce((a, b) => a + b, 0);
      if (total > 0) {
        Object.keys(probabilities).forEach(key => {
          probabilities[key] = Math.round((probabilities[key] / total) * 100);
        });
      }

      return probabilities;
    }

    function updateEndingPreview() {
      const probs = calculateEndings();
      const container = $('#ending-preview');
      container.empty();

      endingTypes.forEach(ending => {
        const percent = probs[ending.key] || 0;
        container.append(`
          <div class="ending-item">
            <span class="ending-name" title="${ending.desc}">${ending.name}</span>
            <div class="ending-bar">
              <div class="ending-fill" style="width: ${percent}%"></div>
            </div>
            <span class="ending-percent">${percent}%</span>
          </div>
        `);
      });
    }

    function updateHistory(result, description, prompt) {
      const time = new Date().toLocaleTimeString('zh-CN', {hour:'2-digit',minute:'2-digit'});
      const record = { time, result, description, prompt };
      rollHistory.unshift(record);
      if (rollHistory.length > 10) rollHistory.pop();

      const container = $('#roll-history');
      container.empty();
      rollHistory.forEach((rec, idx) => {
        container.append(`<div class="history-item" data-index="${idx}">[${rec.time}] ${rec.result}点 - ${rec.description}</div>`);
      });
    }

    function rollDice() {
      const result = Math.floor(Math.random() * 6) + 1;
      $('#dice-value').text(result).addClass('rolling');

      setTimeout(() => {
        $('#dice-value').removeClass('rolling');

        let prompt = '';
        let description = '';

        if (diceMode === 'scene') {
          const sceneList = sceneEvents[result];
          const scene = sceneList[Math.floor(Math.random() * sceneList.length)];
          const assaultList = assaultActions[result];
          const assault = assaultList[Math.floor(Math.random() * assaultList.length)];

          $('#result-content').html(`
            <div class="scene-card">
              <div class="scene-header">
                <div class="scene-badge">${scene.name}</div>
                <div class="scene-type">强度 ${result}/6</div>
              </div>
              <div class="scene-desc">${scene.desc}</div>
              <div class="scene-detail">${scene.detail}</div>
            </div>
            <div class="assault-card">
              <div class="assault-level">
                ${Array(result).fill('<i class="fas fa-fire danger-icon"></i>').join('')}
                <span style="margin-left:4px;font-size:10px;color:var(--text-dim);">侵犯度${result}/6</span>
              </div>
              <div class="assault-text">${assault}</div>
            </div>
          `);

          prompt = `[场景触发]\n\n${scene.name}：\n${scene.desc}\n\n细节：${scene.detail}\n\n接下来：${assault}`;
          description = `${scene.name} + 侵犯行为`;

        } else if (diceMode === 'assault') {
          const assaultList = assaultActions[result];
          const assault = assaultList[Math.floor(Math.random() * assaultList.length)];

          $('#result-content').html(`
            <div class="assault-card">
              <div class="assault-level">
                ${Array(result).fill('<i class="fas fa-fire danger-icon"></i>').join('')}
                <span style="margin-left:4px;font-size:10px;color:var(--text-dim);">侵犯度${result}/6</span>
              </div>
              <div class="assault-text">${assault}</div>
            </div>
          `);

          if (currentNpc) {
            prompt = `${currentNpc}${assault}`;
          } else {
            prompt = `[侵犯行为] ${assault}`;
          }
          description = assault.substring(0, 20) + '...';

        } else if (diceMode === 'luck') {
          const luckList = luckEvents[result];
          const luck = luckList[Math.floor(Math.random() * luckList.length)];

          $('#result-content').html(`
            <div class="scene-card">
              <div class="scene-header">
                <div class="scene-badge">运势判定</div>
                <div class="scene-type">${result}点</div>
              </div>
              <div class="scene-desc" style="font-size:12px;">${luck}</div>
            </div>
          `);

          prompt = `[运势] ${luck}`;
          description = luck;
        }

        updateHistory(result, description, prompt);
        copyToDialog(prompt);
        showToast('已填入对话框', 'success');
      }, 500);
    }

    function randomScenic() {
      const spot = scenicSpots[Math.floor(Math.random() * scenicSpots.length)];
      const prompt = `我前往${spot.name}。\n\n[场景描述]\n${spot.desc}\n\n环境：${spot.env}\n\n场景：${spot.scene}`;
      copyToDialog(prompt);
      showToast(`随机景点: ${spot.name}`, 'success');
    }

    function goToScenic(spotName) {
      const spot = scenicSpots.find(s => s.name === spotName);
      if (spot) {
        const prompt = `我前往${spot.name}。\n\n[场景描述]\n${spot.desc}\n\n环境：${spot.env}\n\n场景：${spot.scene}`;
        copyToDialog(prompt);
        showToast('已填入对话框', 'success');
      }
    }

    function savePlans() {
      try {
        if (typeof localStorage !== 'undefined') {
          localStorage.setItem('xuexiang_plans', JSON.stringify(plotPlans));
        }
      } catch (e) {}
    }

    function loadPlans() {
      try {
        if (typeof localStorage !== 'undefined') {
          const saved = localStorage.getItem('xuexiang_plans');
          if (saved) {
            plotPlans = JSON.parse(saved);
          }
        }
      } catch (e) {}
    }

    function renderPlans() {
      const container = $('#plan-list');
      container.empty();

      if (plotPlans.length === 0) {
        container.html('<div class="empty"><i class="fas fa-clipboard-list"></i><p>暂无计划</p></div>');
        return;
      }

      plotPlans.forEach((plan, index) => {
        container.append(`
          <div class="plan-item">
            <button class="delete-btn" data-index="${index}">
              <i class="fas fa-times"></i>
            </button>
            <div class="plan-type">[${plan.type}]</div>
            <div class="plan-content">${plan.content}</div>
          </div>
        `);
      });
    }

    function addPlan(type, content) {
      plotPlans.push({ type, content });
      savePlans();
      renderPlans();
    }

    function deletePlan(index) {
      plotPlans.splice(index, 1);
      savePlans();
      renderPlans();
    }

    function clearAllPlans() {
      if (confirm('确定清空所有计划吗？')) {
        plotPlans = [];
        savePlans();
        renderPlans();
        showToast('已清空所有计划', 'success');
      }
    }

    function executePlans() {
      if (plotPlans.length === 0) {
        showToast('没有计划可执行', 'error');
        return;
      }

      let prompt = '[执行剧情计划]\n\n';
      plotPlans.forEach((plan, idx) => {
        prompt += `${idx + 1}. [${plan.type}] ${plan.content}\n`;
      });
      prompt += '\n请按照以上计划推进剧情,适当增加侵犯值。';

      copyToDialog(prompt);
      showToast(`已执行${plotPlans.length}个计划`, 'success');
    }

    function openAddPlanModal(type) {
      $('#modal-plan-type').text(type);
      $('#plan-input').val('');
      $('#add-plan-modal').addClass('show').data('type', type);
    }

    function closeAddPlanModal() {
      $('#add-plan-modal').removeClass('show');
    }

    function confirmAddPlan() {
      const type = $('#add-plan-modal').data('type');
      const content = $('#plan-input').val().trim();

      if (!content) {
        showToast('请输入计划内容', 'error');
        return;
      }

      addPlan(type, content);
      closeAddPlanModal();
      showToast('已添加计划', 'success');
    }

    function populateData() {
      const data = getAllVariables();

      const world = _.get(data, 'stat_data.世界', {});
      $('#world-date').text(world.日期 || '未知');
      $('#world-time').text(world.时间 || '未知');
      $('#world-weather').text(world.天气 || '未知');
      $('#world-location').text(world.当前地点 || '未知');

      const npcList = _.get(data, 'stat_data.在场NPC', {});
      const validNpcs = Object.keys(npcList).filter(name => 
        npcList[name] !== '待初始化' && typeof npcList[name] === 'object'
      );

      const selector = $('#npc-selector');
      selector.empty();

      if (validNpcs.length === 0) {
        selector.html('<div class="empty"><i class="fas fa-users"></i><p>当前场景无NPC</p></div>');
        $('#npc-info').html('<div class="empty"><i class="fas fa-user-slash"></i><p>请选择一个NPC</p></div>');
        return;
      }

      validNpcs.forEach((name, idx) => {
        const isActive = name === currentNpc || (!currentNpc && idx === 0);
        if (isActive) currentNpc = name;
        selector.append(`
          <div class="npc-pill ${isActive ? 'active' : ''}" data-npc="${name}">${name}</div>
        `);
      });

      updateNpcInfo(npcList[currentNpc]);
    }

    function updateNpcInfo(npc) {
      const container = $('#npc-info');
      if (!npc) {
        container.html('<div class="empty"><i class="fas fa-user-slash"></i><p>请选择一个NPC</p></div>');
        return;
      }

      const info = npc.基本信息 || {};
      const wear = npc.穿搭 || {};
      const danger = npc.侵犯值 || 0;
      const dangerStage = getDangerStage(danger);

      let html = '<div class="info-card"><div class="card-header"><i class="fas fa-id-card"></i>基本信息</div><div class="info-grid">';
      if (info.年龄 && info.年龄 !== '待初始化') {
        html += `<div class="info-row"><span class="label">年龄</span><span class="value">${info.年龄}</span></div>`;
      }
      if (info.身份 && info.身份 !== '待初始化') {
        html += `<div class="info-row"><span class="label">身份</span><span class="value">${info.身份}</span></div>`;
      }
      if (info.类型 && info.类型 !== '待初始化') {
        html += `<div class="info-row"><span class="label">类型</span><span class="value">${info.类型}</span></div>`;
      }
      if (info.家庭状况 && info.家庭状况 !== '待初始化') {
        html += `<div class="info-row"><span class="label">家庭状况</span><span class="value">${info.家庭状况}</span></div>`;
      }
      html += '</div></div>';

      if (wear.当前穿着 || wear.丝袜) {
        html += '<div class="info-card"><div class="card-header"><i class="fas fa-tshirt"></i>穿搭</div>';
        html += '<div class="wear-details">';
        if (wear.当前穿着 && wear.当前穿着 !== '待初始化') {
          html += `${wear.当前穿着}`;
        }
        if (wear.丝袜 && wear.丝袜 !== '待初始化') {
          html += `<br>丝袜：${wear.丝袜}`;
        }
        html += `<br>本地人：${wear.是否本地人 ? '是(不怕冷)' : '否(怕冷)'}`;
        html += '</div></div>';
      }

      if (npc.性格 && npc.性格 !== '待初始化') {
        html += `<div class="info-card"><div class="card-header"><i class="fas fa-brain"></i>性格</div><div class="info-row"><span class="value">${npc.性格}</span></div></div>`;
      }

      if (npc.当前状态 && npc.当前状态 !== '待初始化') {
        html += `<div class="info-card"><div class="card-header"><i class="fas fa-running"></i>当前状态</div><div class="info-row"><span class="value">${npc.当前状态}</span></div></div>`;
      }

      html += `
        <div class="info-card">
          <div class="card-header"><i class="fas fa-exclamation-triangle"></i>侵犯值</div>
          <div class="danger-box">
            <div class="danger-header">
              <span style="font-size:11px;color:var(--text-dim);">当前数值</span>
              <span class="danger-value">${danger}</span>
            </div>
            <div class="danger-track">
              <div class="danger-fill" style="width: ${danger}%"></div>
            </div>
            <div class="danger-desc">${dangerStage}</div>
          </div>
        </div>`;

      if (npc.内心想法 && npc.内心想法 !== '待初始化') {
        html += `
          <div class="info-card">
            <div class="card-header"><i class="fas fa-comment-dots"></i>内心想法</div>
            <div class="thought-box">
              <div class="thought-text">${npc.内心想法}</div>
            </div>
          </div>`;
      }

      container.html(html);
    }

    function initScenicDropdown() {
      const list = $('#scenic-list');
      list.empty();
      scenicSpots.forEach(spot => {
        list.append(`<div class="dropdown-item" data-name="${spot.name}">${spot.name}</div>`);
      });
    }

    function initDropdown() {
      $(document).on('click', '.dropdown-btn', function(e) {
        e.stopPropagation();
        const dropdown = $(this).closest('.dropdown');
        const list = dropdown.find('.dropdown-list');
        const isOpen = $(this).hasClass('open');

        $('.dropdown-btn').removeClass('open');
        $('.dropdown-list').removeClass('open');

        if (!isOpen) {
          $(this).addClass('open');
          const rect = this.getBoundingClientRect();
          list.css({
            top: rect.bottom + 'px',
            left: rect.left + 'px',
            width: rect.width + 'px'
          });
          list.addClass('open');
        }
      });

      $(document).on('click', '.dropdown-item', function() {
        const name = $(this).data('name');
        if (name) goToScenic(name);
        $('.dropdown-btn').removeClass('open');
        $('.dropdown-list').removeClass('open');
      });

      $(document).on('click', function() {
        $('.dropdown-btn').removeClass('open');
        $('.dropdown-list').removeClass('open');
      });
    }

    const quickCommands = {
      morning: '时间快进到清晨。',
      noon: '时间快进到正午。',
      evening: '时间快进到傍晚。',
      night: '时间快进到深夜。',
      observe: '我观察周围的情况。',
      leave: '我试图离开这里。',
      approach: '她往我这边凑过来。',
      touchme: '她找借口碰我。',
      pretend: '我假装不懂,没接她的话茬。',
      follow: '我顺着她的意思,没拒绝。',
      excuse: '我找借口想脱身。',
      resist: '我推开她,说"别这样"。',
      submit: '我不反抗了,任由她摆弄。'
    };

    function sendCommand(cmd) {
      const text = quickCommands[cmd];
      if (text && copyToDialog(text)) {
        showToast('已填入对话框', 'success');
      }
    }

    async function init() {
      await waitGlobalInitialized('Mvu');

      let savedFont = 'a';
      try {
        if (typeof localStorage !== 'undefined') {
          savedFont = localStorage.getItem('xuexiang_font') || 'a';
        }
      } catch (e) {}
      switchFont(savedFont);

      loadPlans();
      initScenicDropdown();
      initDropdown();
      populateData();
      updateEndingPreview();
      renderPlans();

      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, () => { 
        populateData(); 
        updateEndingPreview();
      });

      $('.font-btn').on('click', function() {
        switchFont($(this).data('font'));
      });

      $('.tab').on('click', function() {
        const tab = $(this).data('tab');
        $('.tab').removeClass('active');
        $(this).addClass('active');
        $('.content').removeClass('active');
        $(`#${tab}`).addClass('active');
      });

      $(document).on('click', '.npc-pill', function() {
        currentNpc = $(this).data('npc');
        $('.npc-pill').removeClass('active');
        $(this).addClass('active');
        const data = getAllVariables();
        const npcList = _.get(data, 'stat_data.在场NPC', {});
        updateNpcInfo(npcList[currentNpc]);
      });

      $('.dice-mode-btn').on('click', function() {
        diceMode = $(this).data('mode');
        $('.dice-mode-btn').removeClass('active');
        $(this).addClass('active');
        $('#result-content').html('<div class="scene-desc" style="text-align:center;color:var(--text-dim);padding:20px;">请投骰...</div>');
      });

      $('.tool-btn').on('click', function() {
        const cmd = $(this).data('cmd');
        if (cmd) sendCommand(cmd);
      });

      $(document).on('click', '.history-item', function() {
        const index = $(this).data('index');
        const record = rollHistory[index];
        if (record && copyToDialog(record.prompt)) {
          showToast('已重新填入', 'success');
        }
      });

      $(document).on('click', '.delete-btn', function() {
        const index = $(this).data('index');
        deletePlan(index);
      });

      $('#btn-roll-dice').on('click', rollDice);
      $('#btn-random-scenic').on('click', randomScenic);
      $('#btn-execute-plans').on('click', executePlans);
      $('#btn-clear-plans').on('click', clearAllPlans);

      $('#btn-add-event').on('click', () => openAddPlanModal('事件计划'));
      $('#btn-add-npc').on('click', () => openAddPlanModal('NPC计划'));
      $('#btn-add-scene').on('click', () => openAddPlanModal('场景计划'));

      $('.modal-close').on('click', closeAddPlanModal);
      $('#btn-confirm-plan').on('click', confirmAddPlan);
      $('#btn-cancel-plan').on('click', closeAddPlanModal);

      $(document).on('click', '.modal', function(e) {
        if ($(e.target).hasClass('modal')) {
          closeAddPlanModal();
        }
      });
    }

    $(errorCatched(init));
  </script>
</head>
<body class="font-a">
  <div class="main-container">
    <div class="top-bar">
      <div class="title">
        <i class="fas fa-snowflake"></i>
        <span>雪乡镇</span>
      </div>
      <div class="font-switcher">
        <button class="font-btn active" data-font="a" title="站酷青柯">青</button>
        <button class="font-btn" data-font="b" title="站酷小薇">薇</button>
        <button class="font-btn" data-font="c" title="马善政">马</button>
        <button class="font-btn" data-font="d" title="思源黑体">黑</button>
      </div>
    </div>

    <div class="world-bar">
      <div class="world-grid">
        <div class="world-item">
          <i class="fas fa-calendar-alt"></i>
          <span id="world-date">未知</span>
        </div>
        <div class="world-item">
          <i class="fas fa-clock"></i>
          <span id="world-time">未知</span>
        </div>
        <div class="world-item weather">
          <i class="fas fa-snowflake"></i>
          <span id="world-weather">未知</span>
        </div>
        <div class="world-item location full">
          <i class="fas fa-map-marker-alt"></i>
          <span id="world-location">未知</span>
        </div>
      </div>
    </div>

    <div class="tabs">
      <button class="tab active" data-tab="npc">
        <i class="fas fa-users"></i>
        NPC
      </button>
      <button class="tab" data-tab="ending">
        <i class="fas fa-chart-line"></i>
        结局
      </button>
      <button class="tab" data-tab="dice">
        <i class="fas fa-dice"></i>
        骰子
      </button>
      <button class="tab" data-tab="plan">
        <i class="fas fa-clipboard-list"></i>
        计划
      </button>
      <button class="tab" data-tab="quick">
        <i class="fas fa-bolt"></i>
        快捷
      </button>
    </div>

    <div class="content active" id="npc">
      <div class="npc-pills" id="npc-selector"></div>
      <div id="npc-info"></div>
    </div>

