      if (npc.内心想法 && npc.内心想法 !== '待初始化') {
        html += `
          <div class="info-card">
            <div class="card-header"><i class="fas fa-comment-dots"></i>内心想法</div>
            <div class="thought-box">
              <div class="thought-text">${npc.内心想法}</div>
            </div>
          </div>`;
      }

      container.html(html);
    }

    function initScenicDropdown() {
      const list = $('#scenic-list');
      list.empty();
      scenicSpots.forEach(spot => {
        list.append(`<div class="dropdown-item" data-name="${spot.name}">${spot.name}</div>`);
      });
    }

    function initDropdown() {
      $(document).on('click', '.dropdown-btn', function(e) {
        e.stopPropagation();
        const dropdown = $(this).closest('.dropdown');
        const list = dropdown.find('.dropdown-list');
        const isOpen = $(this).hasClass('open');

        $('.dropdown-btn').removeClass('open');
        $('.dropdown-list').removeClass('open');

        if (!isOpen) {
          $(this).addClass('open');
          const rect = this.getBoundingClientRect();
          list.css({
            top: rect.bottom + 'px',
            left: rect.left + 'px',
            width: rect.width + 'px'
          });
          list.addClass('open');
        }
      });

      $(document).on('click', '.dropdown-item', function() {
        const name = $(this).data('name');
        if (name) goToScenic(name);
        $('.dropdown-btn').removeClass('open');
        $('.dropdown-list').removeClass('open');
      });

      $(document).on('click', function() {
        $('.dropdown-btn').removeClass('open');
        $('.dropdown-list').removeClass('open');
      });
    }

    const quickCommands = {
      morning: '时间快进到清晨。',
      noon: '时间快进到正午。',
      evening: '时间快进到傍晚。',
      night: '时间快进到深夜。',
      observe: '我观察周围的情况。',
      leave: '我试图离开这里。',
      approach: '她往我这边凑过来。',
      touchme: '她找借口碰我。',
      pretend: '我假装不懂,没接她的话茬。',
      follow: '我顺着她的意思,没拒绝。',
      excuse: '我找借口想脱身。',
      resist: '我推开她,说"别这样"。',
      submit: '我不反抗了,任由她摆弄。'
    };

    function sendCommand(cmd) {
      const text = quickCommands[cmd];
      if (text && copyToDialog(text)) {
        showToast('已填入对话框', 'success');
      }
    }

    async function init() {
      await waitGlobalInitialized('Mvu');

      let savedFont = 'a';
      try {
        if (typeof localStorage !== 'undefined') {
          savedFont = localStorage.getItem('xuexiang_font') || 'a';
        }
      } catch (e) {}
      switchFont(savedFont);

      loadPlans();
      initScenicDropdown();
      initDropdown();
      populateData();
      updateEndingPreview();
      renderPlans();

      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, () => { 
        populateData(); 
        updateEndingPreview();
      });

      $('.font-btn').on('click', function() {
        switchFont($(this).data('font'));
      });

      $('.tab').on('click', function() {
        const tab = $(this).data('tab');
        $('.tab').removeClass('active');
        $(this).addClass('active');
        $('.content').removeClass('active');
        $(`#${tab}`).addClass('active');
      });

      $(document).on('click', '.npc-pill', function() {
        currentNpc = $(this).data('npc');
        $('.npc-pill').removeClass('active');
        $(this).addClass('active');
        const data = getAllVariables();
        const npcList = _.get(data, 'stat_data.在场NPC', {});
        updateNpcInfo(npcList[currentNpc]);
      });

      $('.dice-mode-btn').on('click', function() {
        diceMode = $(this).data('mode');
        $('.dice-mode-btn').removeClass('active');
        $(this).addClass('active');
        $('#result-content').html('<div class="scene-desc" style="text-align:center;color:var(--text-dim);padding:20px;">请投骰...</div>');
      });

      $('.tool-btn').on('click', function() {
        const cmd = $(this).data('cmd');
        if (cmd) sendCommand(cmd);
      });

      $(document).on('click', '.history-item', function() {
        const index = $(this).data('index');
        const record = rollHistory[index];
        if (record && copyToDialog(record.prompt)) {
          showToast('已重新填入', 'success');
        }
      });

      $(document).on('click', '.ending-name', function(e) {
        e.stopPropagation();
        const endingKey = $(this).data('ending');
        showEndingDetail(endingKey);
      });

      $(document).on('click', '.delete-btn', function() {
        const index = $(this).data('index');
        deletePlan(index);
      });

      $('#btn-roll-dice').on('click', rollDice);
      $('#btn-random-scenic').on('click', randomScenic);
      $('#btn-execute-plans').on('click', executePlans);
      $('#btn-clear-plans').on('click', clearAllPlans);

      $('#btn-add-event').on('click', () => openAddPlanModal('事件计划'));
      $('#btn-add-npc').on('click', () => openAddPlanModal('NPC计划'));
      $('#btn-add-scene').on('click', () => openAddPlanModal('场景计划'));

      $('.modal-close').on('click', function() {
        const modal = $(this).closest('.modal');
        modal.removeClass('show');
      });

      $('#btn-confirm-plan').on('click', confirmAddPlan);
      $('#btn-cancel-plan').on('click', closeAddPlanModal);

      $(document).on('click', '.modal', function(e) {
        if ($(e.target).hasClass('modal')) {
          $(this).removeClass('show');
        }
      });
    }

    $(errorCatched(init));
  </script>
</head>
